import{_ as a,C as o,o as n,c as r,E as i,a2 as s}from"./chunks/framework.CkaEw-3u.js";const u=JSON.parse('{"title":"Stagger Animations Across Characters","description":"Duplicate one keyframe animation across characters and parts with a time offset","frontmatter":{"title":"Stagger Animations Across Characters","description":"Duplicate one keyframe animation across characters and parts with a time offset","pageClass":"feature-guide","aside":false,"head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/en/features/feature-offset-animation.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Stagger Animations Across Characters | Mug Typography Manual"}],["meta",{"property":"og:description","content":"Duplicate one keyframe animation across characters and parts with a time offset"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/en/features/feature-offset-animation.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"Stagger Animations Across Characters | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"Duplicate one keyframe animation across characters and parts with a time offset"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"en/features/feature-offset-animation.md","filePath":"en/features/feature-offset-animation.md"}'),c={name:"en/features/feature-offset-animation.md"};function p(m,e,l,h,g,d){const t=o("FeatureHero");return n(),r("div",null,[i(t,{language:"en","is-new":"",eyebrow:"OFFSET ANIMATION",title:"Turn one motion into a sequence",description:"Duplicate a keyframe animation created on one character across other characters and parts with an automatic time offset. Just set a Frame Offset to quickly build cascading, follower-style motion where characters start moving one after another.",image:"/image/offset-animation.webp","image-alt":"Characters animated with staggered start times","detail-link":"/en/reference/reference-copy-paste#paste-animation-with-offset","point-one":"Propagate from one motion","point-two":"Stagger with Frame Offset","point-three":"Free ordering of targets"}),e[0]||(e[0]=s('<h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><ol><li>Create a keyframe animation on one source character or part.</li><li>Set <strong>Page</strong> to <code>Copy / Paste</code>.</li><li>Select the character or part you animated in step 1 and click <strong>Copy Selection</strong>.</li><li>Under <strong>Paste Target Attributes</strong>, enable the animation items to duplicate.</li><li>Select multiple destination characters or parts in the viewer.</li><li>Enter the number of frames between destinations in <strong>Frame Offset</strong>.</li><li>Click <strong>Paste Animation with Offset</strong>.</li></ol><p>With the copy source as the reference (no shift), the complete animation is duplicated onto the destinations with cumulative delays of 1×, 2×, ... the <strong>Frame Offset</strong>. A <strong>Frame Offset</strong> of <code>3</code> delays each successive destination by three frames; <code>-3</code> staggers them in the opposite time direction.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Any animation already set on the destination characters and parts is erased for the checked parameters and replaced with the copied one.</p></div><h2 id="notes-for-the-fusion-page" tabindex="-1">Notes for the Fusion Page <a class="header-anchor" href="#notes-for-the-fusion-page" aria-label="Permalink to &quot;Notes for the Fusion Page&quot;">​</a></h2><p>The Fusion page in DaVinci Resolve does not support direct animation copying by OFX plugins, so the operation may take longer than on the Edit page and extra keyframes may be created.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>On the Fusion page, after step 7 <strong>wait a few seconds for the keyframes to settle</strong>, then click <strong>Repair Animation Paste</strong> without changing the selection or checked targets. This removes keyframes placed at unexpected times and cleans up the offsets.</p></div><h2 id="specifying-the-order" tabindex="-1">Specifying the Order <a class="header-anchor" href="#specifying-the-order" aria-label="Permalink to &quot;Specifying the Order&quot;">​</a></h2><p>By default, offsets accumulate in logical index order (<code>c1</code>, <code>c2</code>, ...). List characters and parts in <strong>Order</strong> to accumulate offsets in that sequence instead.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>c3 c1 c2</span></span></code></pre></div><p>In the example above, character 3 starts first (<code>Frame Offset × 1</code>), character 1 next (<code>Frame Offset × 2</code>), and so on. The syntax matches Write On Manual Order, and ranges such as <code>p2-p5</code> can also be used. Unlisted destinations follow in logical index order.</p><p>For the full specification (axis handling of 2D parameters, keyframe requirements for color channels, and more), see <a href="/mug-typography-docs/en/reference/reference-copy-paste.html#paste-animation-with-offset">Copy / Paste</a>.</p>',12))])}const y=a(c,[["render",p]]);export{u as __pageData,y as default};
